import { useState, forwardRef, useImperativeHandle } from "react";

const NestedList = forwardRef((props, ref) => {
  const [root, setRoot] = useState({
    title: "Список уроков",
    collapsed: false,
    Modules: []
  });

  // Экспонируем метод getData родителю
  useImperativeHandle(ref, () => ({
    getData: () => root,
    loadData: (data) => setRoot(data)
  }));

  // --- ROOT FUNCTIONS ---
  const toggleRoot = () => setRoot(prev => ({ ...prev, collapsed: !prev.collapsed }));
  const addChild = () => {
    setRoot(prev => ({
      ...prev,
      Modules: [
        ...prev.Modules,
        { Id: crypto.randomUUID(), title: "", Lessons: [], collapsed: false }
      ]
    }));
  };

  const deleteChild = (childId) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev.Modules.filter(c => c.Id !== childId)
    }));
  };

  // --- CHILD FUNCTIONS ---
  const toggleChild = (Id) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev?.Modules?.map(c =>
        c.Id === Id ? { ...c, collapsed: !c.collapsed } : c
      )
    }));
  };

  const updateChildTitle = (Id, value) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev?.Modules?.map(c =>
        c.Id === Id ? { ...c, title: value } : c
      )
    }));
  };

  const addField = (childId) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev?.Modules?.map(c =>
        c.Id === childId
          ? {
              ...c,
              Lessons: [...c.Lessons, { Id: crypto.randomUUID(), value: "" }]
            }
          : c
      )
    }));
  };

  const updateField = (childId, fieldId, value) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev?.Modules?.map(c =>
        c.Id === childId
          ? {
              ...c,
              Lessons: c.Lessons?.map(f =>
                f.Id === fieldId ? { ...f, value } : f
              )
            }
          : c
      )
    }));
  };

  const deleteField = (childId, fieldId) => {
    setRoot(prev => ({
      ...prev,
      Modules: prev?.Modules?.map(c =>
        c.Id === childId
          ? { ...c, Lessons: c.Lessons.filter(f => f.Id !== fieldId) }
          : c
      )
    }));
  };

  return (
    <div style={{ border: "1px solid #aaa", padding: 10, margin: 10 }}>
      {/* ROOT HEADER */}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <svg
          onClick={toggleRoot}
          style={{
            width: 20,
            height: 20,
            cursor: "pointer",
            transform: root.collapsed ? "rotate(0deg)" : "rotate(180deg)",
            transition: "0.2s"
          }}
        >
          <use href="#icon-expand" />
        </svg>
        <h2 style={{ margin: 0, flex: 1 }}>{root.Title}</h2>

        <svg
          onClick={addChild}
          style={{ width: 20, height: 20, cursor: "pointer" }}
        >
          <use href="#icon-plus" />
        </svg>
      </div>

      {/* ROOT CONTENT */}
      {!root.collapsed && (
        <div style={{ marginLeft: 25, marginTop: 10 }}>
          {root?.Modules?.map((child) => (
            <div
              key={child.Id}
              style={{
                border: "1px solid #ccc",
                padding: 8,
                marginBottom: 8,
                borderRadius: 6,
                background: "#fafafa"
              }}
            >
              {/* CHILD HEADER */}
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <svg
                  onClick={() => toggleChild(child.Id)}
                  style={{
                    width: 18,
                    height: 18,
                    cursor: "pointer",
                    transform: child.collapsed ? "rotate(0deg)" : "rotate(180deg)",
                    transition: "0.2s"
                  }}
                >
                  <use href="#icon-expand" />
                </svg>

                <input
                  placeholder="Название списка"
                  value={child.Title}
                  onChange={(e) => updateChildTitle(child.Id, e.target.value)}
                  className="input mini-input"
                  style={{height:"20px"}}
                />

                <svg
                  onClick={() => addField(child.Id)}
                  style={{ width: 18, height: 18, cursor: "pointer" }}
                >
                  <use href="#icon-plus" />
                </svg>

                <span
                  onClick={() => deleteChild(child.Id)}
                  style={{ color: "red", cursor: "pointer" }}
                >
                  Удалить
                </span>
              </div>

              {/* CHILD CONTENT */}
              {!child.collapsed && (
                <div style={{ marginLeft: 20, marginTop: 6 }}>
                  {module?.Lessons?.map((f) => (
                    <div
                      key={f.Id}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        marginBottom: 4
                      }}
                    >
                      <input
                        value={f.value}
                        onChange={(e) =>
                          updateField(child.Id, f.Id, e.target.value)
                        }
                        className="input mini-input"
                        style={{ height:"20px" }}
                      />
                      <span
                        onClick={() => deleteField(child.Id, f.Id)}
                        style={{ color: "red", cursor: "pointer" }}
                      >
                        Удалить
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
});

export { NestedList };
